[metadata] {"type": "create", "filePath": "/app/packages/vitest/src/node/sequencers/duration-smoothing.ts", "content": "export type DurationSmoothing = 'latest' | 'average' | 'p95' | 'median'

export interface DurationObservation {
  duration: number
  recordedAt: number
}

/**
 * Reduce a set of duration observations for a single file to a single duration
 * value using the given smoothing strategy.
 *
 * The `observations` array is expected to be non-empty.
 */
export function smoothDurations(
  observations: DurationObservation[],
  strategy: DurationSmoothing,
): number {
  switch (strategy) {
    case 'latest': {
      let latest = observations[0]
      for (const observation of observations) {
        if (observation.recordedAt > latest.recordedAt) {
          latest = observation
        }
      }
      return latest.duration
    }
    case 'average': {
      const sum = observations.reduce((acc, o) => acc + o.duration, 0)
      return Math.round(sum / observations.length)
    }
    case 'p95': {
      const sorted = observations.map(o => o.duration).sort((a, b) => a - b)
      const n = sorted.length
      const index = Math.ceil(0.95 * n) - 1
      return sorted[Math.min(Math.max(index, 0), n - 1)]
    }
    case 'median': {
      const sorted = observations.map(o => o.duration).sort((a, b) => a - b)
      const n = sorted.length
      if (n % 2 === 1) {
        return sorted[Math.floor(n / 2)]
      }
      const a = sorted[n / 2 - 1]
      const b = sorted[n / 2]
      return Math.floor((a + b) / 2)
    }
  }
}
