import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'node:fs'
import { dirname } from 'pathe'
import { smoothDurations } from './duration-smoothing'

/** Single, most-recent observation stored inline. */
export interface SingleDurationEntry {
  duration: number
  recordedAt: number
}

/** Multiple observations for a single file. */
export interface MultiDurationEntry {
  observations: DurationObservation[]
}

/** Legacy format: a plain number of milliseconds. */
export type LegacyDurationEntry = number

export type DurationHistoryEntry
  = | SingleDurationEntry
    | MultiDurationEntry
    | LegacyDurationEntry

export type RawDurationHistory = Record<string, DurationHistoryEntry>

export interface ReadDurationHistoryOptions {
  /** Time-to-live for observations in milliseconds. `0` disables expiry. */
  ttl?: number
  /** Smoothing strategy applied to non-expired observations. */
  smoothing?: DurationSmoothing
  /** Current timestamp, used for TTL calculations. */
  now?: number
}

export interface WriteDurationHistoryOptions {
  /** Maximum number of observations written per file. */
  maxRuns?: number
  /** Current timestamp, stored as `recordedAt`. */
  now?: number
}

/**
 * Normalize a raw history entry into a list of observations. Supports the
 * single-entry, multi-entry, and legacy number formats.
 */
export function parseHistoryEntry(entry: DurationHistoryEntry): DurationObservation[] {
  if (typeof entry === 'number') {
    // Legacy format -- migrate to a single observation that never expires.
    if (!Number.isFinite(entry)) {
      return []
    }
    return [{ duration: entry, recordedAt: 0 }]
  }

  if (entry && typeof entry === 'object') {
    if (Array.isArray((entry as MultiDurationEntry).observations)) {
      return (entry as MultiDurationEntry).observations.filter(
        o => o && typeof o.duration === 'number' && typeof o.recordedAt === 'number',
      )
    }
    const single = entry as SingleDurationEntry
    if (typeof single.duration === 'number' && typeof single.recordedAt === 'number') {
      return [{ duration: single.duration, recordedAt: single.recordedAt }]
    }
  }

  return []
}

/**
 * Read the raw duration history file. Returns `null` when the file is missing
 * or corrupt.
 */
export function readRawDurationHistory(path: string): RawDurationHistory | null {
  if (!existsSync(path)) {
    return null
  }
  try {
    const content = readFileSync(path, 'utf-8')
    const parsed = JSON.parse(content)
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
      return null
    }
    return parsed as RawDurationHistory
  }
  catch {
    return null
  }
}

/**
 * Read the duration history file and reduce it to a map of
 * slash-normalized-path -> smoothed duration (in milliseconds).
 *
 * Returns `null` when the file is missing or corrupt.
 */
export function readDurationHistory(
  path: string,
  options: ReadDurationHistoryOptions = {},
): Map<string, number> | null {
  const raw = readRawDurationHistory(path)
  if (raw == null) {
    return null
  }

  const ttl = options.ttl ?? 0
  const smoothing = options.smoothing ?? 'latest'
  const now = options.now ?? Date.now()
  const cutoff = ttl > 0 ? now - ttl : null

  const durations = new Map<string, number>()

  for (const key of Object.keys(raw)) {
    let observations = parseHistoryEntry(raw[key])
    if (cutoff != null) {
      // `recordedAt === 0` never expires (legacy/pinned observations).
      observations = observations.filter(
        o => o.recordedAt === 0 || o.recordedAt >= cutoff,
      )
    }
    if (observations.length === 0) {
      continue
    }
    durations.set(key, smoothDurations(observations, smoothing))
  }

  return durations
}

/**
 * Write duration observations for the given files to the history file,
 * preserving entries for files that are not part of `durations`.
 */
export function writeDurationHistory(
  path: string,
  durations: Map<string, number>,
  options: WriteDurationHistoryOptions = {},
): void {
  const maxRuns = options.maxRuns ?? 1
  const now = options.now ?? Date.now()

  const existing = readRawDurationHistory(path) ?? {}
  const result: RawDurationHistory = { ...existing }

  for (const [key, duration] of durations) {
    const rounded = Math.round(duration)
    const previous = key in existing ? parseHistoryEntry(existing[key]) : []
    const observations = [...previous, { duration: rounded, recordedAt: now }]
