/** Minimal logger surface used for analytics warnings. */
export interface AnalyticsLogger {
  warn: (message: string) => void
}

function createBuckets<T>(count: number): ShardItem<T>[][] {
  return Array.from({ length: count }, () => [])
}

/** Total duration load of a shard bucket. */
function bucketLoad<T>(bucket: ShardItem<T>[]): number {
  return bucket.reduce((acc, item) => acc + item.duration, 0)
}

/**
 * Assign the given items into `count` buckets using LPT (longest processing
 * time) bin-packing, taking pre-existing bucket loads into account.
 *
 * Items are assigned in descending duration order; each item goes to the bucket
 * with the lowest total load, ties broken towards the lowest-indexed bucket.
 */
export function lptInto<T>(
  buckets: ShardItem<T>[][],
  items: ShardItem<T>[],
): void {
  const loads = buckets.map(bucketLoad)
  const sorted = [...items].sort(
    (a, b) => b.duration - a.duration || (a.path < b.path ? -1 : a.path > b.path ? 1 : 0),
  )
  for (const item of sorted) {
    let target = 0
    for (let i = 1; i < loads.length; i++) {
      if (loads[i] < loads[target]) {
        target = i
      }
    }
    buckets[target].push(item)
    loads[target] += item.duration
  }
}

/**
 * LPT bin-packing across `count` shards.
 */
export function lptPack<T>(items: ShardItem<T>[], count: number): ShardItem<T>[][] {
  const buckets = createBuckets<T>(count)
  lptInto(buckets, items)
  return buckets
}

/**
 * Round-robin packing with a bouncing pointer. Items are sorted by descending
 * duration (path ascending as tie-break). The pointer starts at 0 moving
 * forward; when it would leave the valid range it is clamped to the boundary
 * shard and reverses direction, so boundary shards receive two consecutive
 * assignments.
 */
export function roundRobinPack<T>(items: ShardItem<T>[], count: number): ShardItem<T>[][] {
  const buckets = createBuckets<T>(count)
  const sorted = [...items].sort(
    (a, b) => b.duration - a.duration || (a.path < b.path ? -1 : a.path > b.path ? 1 : 0),
  )
  let pointer = 0
  let direction = 1
  for (const item of sorted) {
    buckets[pointer].push(item)
    let next = pointer + direction
    if (next < 0) {
      next = 0
      direction = 1
    }
    else if (next >= count) {
      next = count - 1
      direction = -1
    }
    pointer = next
  }
  return buckets
}

/**
 * Equal-split packing: items are sorted by path ascending and distributed
 * across shards by index (`i % count`).
 */
export function equalSplitPack<T>(items: ShardItem<T>[], count: number): ShardItem<T>[][] {
  const buckets = createBuckets<T>(count)
  const sorted = [...items].sort(
    (a, b) => (a.path < b.path ? -1 : a.path > b.path ? 1 : 0),
  )
  sorted.forEach((item, i) => {
    buckets[i % count].push(item)
  })
