 * files together with all remaining files. Otherwise remaining files are
 * distributed with LPT bin-packing.
 */
export function isolateSlowPack<T>(
  items: ShardItem<T>[],
  count: number,
  threshold: number,
): ShardItem<T>[][] {
  const byDuration = (a: ShardItem<T>, b: ShardItem<T>) =>
    b.duration - a.duration || (a.path < b.path ? -1 : a.path > b.path ? 1 : 0)

  const slow = items.filter(item => item.duration > threshold).sort(byDuration)
  const remaining = items.filter(item => item.duration <= threshold).sort(byDuration)
  const buckets = createBuckets<T>(count)

  if (slow.length >= count) {
    for (let i = 0; i < count; i++) {
      buckets[i].push(slow[i])
    }
    const extras = slow.slice(count)
    buckets[count - 1].push(...extras, ...remaining)
  }
  else {
    for (let i = 0; i < slow.length; i++) {
      buckets[i].push(slow[i])
    }
    lptInto(buckets, remaining)
  }

  return buckets
}

/**
 * Emit a warning when the shard load distribution is unbalanced, i.e. when
 * `minLoad / maxLoad < threshold`.
 */
export function checkRebalance<T>(
  buckets: ShardItem<T>[][],
  threshold: number,
  logger: AnalyticsLogger,
): void {
  if (!(threshold > 0)) {
    return
  }
  const loads = buckets.map(bucketLoad)
  const maxLoad = Math.max(...loads)
  const minLoad = Math.min(...loads)
  if (maxLoad <= 0) {
    return
  }
  const ratio = minLoad / maxLoad
  if (ratio < threshold) {
    logger.warn(
      `[vitest] Shard load imbalance detected: ratio=${ratio.toFixed(2)} `
      + `is below threshold=${threshold.toFixed(2)}.`,
    )
  }
}
