import pm from 'picomatch'
import { lptInto } from './shard-analytics'

export interface ShardAffinityRule {
  /** Glob pattern matched against the slash-normalized file path. */
  pattern: string
  /** Target shard index (0-based). Clamped to `shardCount - 1`. */
  shardIndex: number
}

/**
 * Assign files to shards using affinity rules. Each file is matched against the
 * rules in order; the first matching rule wins and pins the file to its
 * (clamped) shard index. Files that match no rule are distributed with LPT
 * bin-packing, taking the loads of affinity-assigned files into account.
 *
 * Returns `null` when no rule matches any file, signalling that the caller
 * should fall back to the `time` strategy.
 */
export function affinityPack<T>(
  items: ShardItem<T>[],
  rules: ShardAffinityRule[],
  count: number,
): ShardItem<T>[][] | null {
  const matchers = rules.map(rule => ({
    isMatch: pm(rule.pattern),
    shardIndex: Math.min(Math.max(rule.shardIndex, 0), count - 1),
  }))

  const buckets: ShardItem<T>[][] = Array.from({ length: count }, () => [])
  const unmatched: ShardItem<T>[] = []
  let anyMatched = false

  for (const item of items) {
    let assigned = false
    for (const matcher of matchers) {
      if (matcher.isMatch(item.path)) {
        buckets[matcher.shardIndex].push(item)
        assigned = true
        anyMatched = true
        break
      }
    }
    if (!assigned) {
      unmatched.push(item)
    }
  }

  if (!anyMatched) {
    return null
  }

  lptInto(buckets, unmatched)
  return buckets
}
