const SHARD_STRATEGIES = ['hash', 'time', 'round-robin', 'affinity']
const DURATION_SMOOTHINGS = ['latest', 'average', 'p95', 'median']
const DURATION_FALLBACK_STRATEGIES = ['hash', 'equal-split']

/**
