 */
function validateShardingOptions(sequence: ResolvedConfig['sequence']): void {
  const fail = (message: string): never => {
    throw new Error(`Vitest: invalid "sequence" configuration. ${message}`)
  }

  if (!SHARD_STRATEGIES.includes(sequence.shardStrategy)) {
    fail(`"shardStrategy" must be one of ${SHARD_STRATEGIES.join(', ')}, received "${sequence.shardStrategy}".`)
