  if (typeof sequence.balanceShardsByTime !== 'boolean') {
    fail(`"balanceShardsByTime" must be a boolean.`)
  }
  if (typeof sequence.recordFileDurations !== 'boolean') {
    fail(`"recordFileDurations" must be a boolean.`)
