  /**
   * Persist the duration of each executed test file to the duration history
   * file, when `sequence.recordFileDurations` is enabled.
   */
  private recordFileDurations(): void {
    const sequence = this.config.sequence
    if (!sequence.recordFileDurations) {
      return
    }

    const durations = new Map<string, number>()
    for (const file of this.state.getFiles()) {
      const duration = file.result?.duration
      if (duration == null) {
        continue
      }
      const key = slash(relative(this.config.root, file.filepath))
      durations.set(key, Math.round(duration))
    }

    if (durations.size === 0) {
      return
    }

    try {
      const path = resolve(this.config.root, sequence.durationHistoryPath)
      writeDurationHistory(path, durations, {
        maxRuns: sequence.durationHistoryMaxRuns,
      })
    }
    catch (error) {
      this.logger.error('Failed to record file durations', error)
    }
  }

