describe('duration smoothing', () => {
  const obs = (duration: number, recordedAt: number) => ({ duration, recordedAt })

  test('latest picks highest recordedAt', () => {
    expect(smoothDurations([obs(10, 1), obs(30, 3), obs(20, 2)], 'latest')).toBe(30)
  })
  test('average rounds', () => {
    expect(smoothDurations([obs(10, 1), obs(11, 2)], 'average')).toBe(11)
  })
  test('p95 index', () => {
    const observations = Array.from({ length: 100 }, (_, i) => obs(i + 1, i))
    // ceil(0.95 * 100) - 1 = 94 -> value 95
    expect(smoothDurations(observations, 'p95')).toBe(95)
  })
  test('p95 single', () => {
    expect(smoothDurations([obs(42, 0)], 'p95')).toBe(42)
  })
  test('median odd', () => {
    expect(smoothDurations([obs(1, 0), obs(3, 1), obs(2, 2)], 'median')).toBe(2)
  })
  test('median even uses floor of avg', () => {
    expect(smoothDurations([obs(1, 0), obs(2, 1), obs(3, 2), obs(4, 3)], 'median')).toBe(2)
  })
})

describe('duration history parsing', () => {
  test('legacy number migrates to recordedAt 0', () => {
    expect(parseHistoryEntry(5000)).toEqual([{ duration: 5000, recordedAt: 0 }])
  })
  test('single entry', () => {
    expect(parseHistoryEntry({ duration: 12, recordedAt: 34 })).toEqual([{ duration: 12, recordedAt: 34 }])
  })
  test('multi entry', () => {
    expect(parseHistoryEntry({ observations: [{ duration: 1, recordedAt: 2 }] })).toEqual([{ duration: 1, recordedAt: 2 }])
  })
})

describe('readDurationHistory', () => {
  test('missing returns null', () => {
    expect(readDurationHistory(join(dir, 'nope.json'))).toBeNull()
  })
  test('corrupt returns null', () => {
    const p = join(dir, 'h.json')
    writeFileSync(p, 'not json{')
    expect(readDurationHistory(p)).toBeNull()
  })
  test('reads and smooths', () => {
    const p = join(dir, 'h.json')
    writeFileSync(p, JSON.stringify({
      'test/a.ts': { observations: [{ duration: 10, recordedAt: 1 }, { duration: 30, recordedAt: 3 }] },
      'test/b.ts': 500,
    }))
    const map = readDurationHistory(p, { smoothing: 'average' })!
    expect(map.get('test/a.ts')).toBe(20)
    expect(map.get('test/b.ts')).toBe(500)
  })
  test('ttl drops old observations but keeps recordedAt 0', () => {
    const p = join(dir, 'h.json')
    const now = 1_000_000
    writeFileSync(p, JSON.stringify({
      'test/a.ts': { observations: [{ duration: 10, recordedAt: now - 5000 }, { duration: 99, recordedAt: now - 50 }] },
      'test/legacy.ts': { duration: 7, recordedAt: 0 },
    }))
    const map = readDurationHistory(p, { ttl: 1000, now, smoothing: 'latest' })!
    expect(map.get('test/a.ts')).toBe(99)
    expect(map.get('test/legacy.ts')).toBe(7)
  })
  test('ttl fully expired file omitted', () => {
    const p = join(dir, 'h.json')
    const now = 1_000_000
    writeFileSync(p, JSON.stringify({ 'test/a.ts': { duration: 10, recordedAt: now - 5000 } }))
    const map = readDurationHistory(p, { ttl: 1000, now })!
    expect(map.has('test/a.ts')).toBe(false)
  })
})

